// Define a middleware function to resolve dynamic routes
var resolveRoute = function(url) {
  // Extract the route parameters from the URL
  var params = url.split(/\//);
  // Check if the route parameters match the pattern
  var pattern = /^\d+$/;
  var param = params[params.length - 1];
  if (param.startsWith("/") === false) return false;
  if (param.length === 0) return false;
  if (!pattern.test(param.substring(1))) {
    // If the pattern does not match, return false
    return false;
  }
  // If the pattern matches, return true
  return true;
}

// Example usage
console.log(resolveRoute("/users/123")); // Output: true
console.log(resolveRoute("/users/abc")); // Output: false

