// Define a class with a method to resolve dynamic routes
class RouteResolver:
  def __init__(self):
    pass

  def resolve(self, url):
    # Extract the route parameters from the URL
    params = url.split("/")
    # Check if the route parameters match the pattern
    pattern = re.compile("^\d+$")
    param = params[-1]
    if param.startswith("/") == False:
      return False
    if param == "":
      return False
    if not pattern.match(param[1:]):
      # If the pattern does not match, return False
      return False
    # If the pattern matches, return True
    return True

# Example usage
resolver = RouteResolver()
print(resolver.resolve("/users/123")) # Output: True
print(resolver.resolve("/users/abc")) # Output: False
